import androidx.appcompat.app.AppCompatActivity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val intent = intent
        if (intent.action == Intent.ACTION_SEND || intent.action == Intent.ACTION_SEND_MULTIPLE) {
            val type = intent.type
            if (type != null && (type.startsWith("text/plain") || type.startsWith("image/*"))) {
                val uriList: ArrayList<Uri>
                if (intent.clipData != null) {
                    uriList = ArrayList(intent.clipData!!.itemCount)
                    for (i in 0 until intent.clipData!!.itemCount) {
                        uriList.add(intent.clipData!!.getItemAt(i).uri)
                    }
                } else {
                    uriList = arrayListOf(intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))
                }

                for (uri in uriList) {
                    when (type) {
                        "text/plain" -> {
                            val content = intent.getStringExtra(Intent.EXTRA_TEXT)
                            Log.d("SharedContent", "Text: $content")
                            // Process the text here
                        }
                        "image/*" -> {
                            val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
                            Log.d("SharedContent", "Image: ${bitmap.width}x${bitmap.height}")
                            // Process the image here
                        }
                    }
                }
            }
        }
    }
}